<?php
declare(strict_types=1);
require dirname(__DIR__).'/app/core/Env.php';\App\Core\Env::load(dirname(__DIR__).'/.env');spl_autoload_register(function(string $class):void{$p='App\\';if(!str_starts_with($class,$p))return;$parts=explode('\\',substr($class,strlen($p)));$parts[0]=strtolower($parts[0]);$f=dirname(__DIR__).'/app/'.implode('/',$parts).'.php';if(is_file($f))require_once $f;});$composer=dirname(__DIR__).'/vendor/autoload.php';if(is_file($composer))require_once $composer;
$pdo=\App\Core\Database::connection();$plans=$pdo->query("SELECT * FROM asset_replacement_plans WHERE replacement_target_date IS NOT NULL")->fetchAll();$created=0;foreach($plans as $p){$days=(int)((strtotime($p['replacement_target_date'])-strtotime(date('Y-m-d')))/86400);$type=$days<0?'overdue':($days<=30?'due':($days<=90?'approaching':null));if(!$type)continue;$severity=$type==='overdue'?'critical':($type==='due'?'warning':'info');$message=ucfirst($p['asset_type']).' #'.$p['asset_id'].' replacement is '.($days<0?abs($days).' days overdue':'due in '.$days.' days').'.';$s=$pdo->prepare("INSERT IGNORE INTO asset_replacement_alerts(asset_replacement_plan_id,alert_type,severity,message) VALUES(?,?,?,?)");$s->execute([$p['id'],$type,$severity,$message]);if($s->rowCount()){$created++;(new \App\Services\NotificationRouteService())->emit('asset.replacement_'.$type,$severity,'Asset replacement alert',$message,rtrim((string)\App\Core\Env::get('APP_URL',''),'/').'/portal/asset-alerts',['plan_id'=>$p['id']]);}}
echo "Created {$created} asset replacement alerts.\n";
